using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed.
            // EF Core 9 writes "$type" instead of "Discriminator".
            // Existing 500K documents and direct SQL queries (c.Discriminator)
            // depend on the old name, so we opt back in explicitly.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — Resource-id format changed.
            // EF Core 8: id = "Product|123"   EF Core 9: id = "123"
            // Existing documents use the old format.  A custom ValueGenerator
            // keeps producing "Product|{key}" so reads and writes still match.
            entity.Property<string>("__id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();

            // BREAKING CHANGE 3 — HasIndex() now throws for the Cosmos provider.
            // Cosmos DB manages indexes at the container level via indexing policy;
            // EF Core 8 silently ignored HasIndex, EF Core 9 rejects it.
            // REMOVED: entity.HasIndex(p => p.Sku);
        });
    }
}

/// <summary>
/// Reproduces the EF Core 8 Cosmos id format: "{EntityTypeName}|{KeyValue}".
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    protected override string NextValue(EntityEntry entry)
    {
        var entityType = entry.Metadata.ShortName();
        var key = entry.Property("Id").CurrentValue;
        return $"{entityType}|{key}";
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; }
}

