using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // BREAKING CHANGE 4 — Synchronous query APIs removed from the Cosmos provider.
    // ToList(), First(), Single(), etc. now throw InvalidOperationException.
    // All queries must use their async counterparts.
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved the "Discriminator"
        // JSON property name in OnModelCreating.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products
            .Where(p => p.Sku == "ABC")
            .ToListAsync();
    }
}

